--
-- Table structure for table `rewards`
--

DROP TABLE IF EXISTS `rewards`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rewards` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int DEFAULT '0',
  `reward_type` varchar(255) DEFAULT NULL,
  `reward_token` varchar(255) DEFAULT NULL,
  `description` text,
  `reward_point` double NOT NULL DEFAULT '0',
  `claim_status` tinyint(1) NOT NULL DEFAULT '0',
  `contract_update` tinyint(1) NOT NULL DEFAULT '0',
  `wallet_found` tinyint(1) NOT NULL DEFAULT '0',
  `chain` enum('MATIC','BNB') NOT NULL DEFAULT 'MATIC',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=144 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

