CREATE TABLE `users_data` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `password` varchar(255) DEFAULT NULL,
  `googleId` varchar(255) DEFAULT NULL,
  `GoogleLogin` tinyint(1) DEFAULT '0',
  `GitHubLogin` tinyint(1) DEFAULT '0',
  `githubId` varchar(255) DEFAULT NULL,
  `wallet_address` varchar(255) DEFAULT NULL,
  `walletLogin` tinyint(1) DEFAULT NULL,
  `token_balance` double NOT NULL DEFAULT '0',
  `referral_code` varchar(255) DEFAULT NULL,
  `referred_by` int DEFAULT '0',
  `account_type` int NOT NULL DEFAULT '0',
  `plan` enum('free','paid') NOT NULL DEFAULT 'free',
  `paid_status` enum('0','1') NOT NULL DEFAULT '0',
  `community` varchar(50) DEFAULT NULL,
  `reset_password_otp` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `login_time` timestamp NULL DEFAULT NULL,
  `streaks` int DEFAULT '0',
  `airdrops` int DEFAULT '0',
  `twitter_name` varchar(255) DEFAULT NULL,
  `x_userName` varchar(255) DEFAULT NULL,
  `telegram_chat_id` varchar(255) DEFAULT NULL,
  `telegramId` varchar(20) DEFAULT NULL,
  `chatId` varchar(20) DEFAULT NULL,
  `avatar` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`email`),
  UNIQUE KEY `chatId` (`chatId`)
) ENGINE=InnoDB AUTO_INCREMENT=74 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
